// In the button section, update to:
<button
  onClick={() => submitPipeline(nodes, edges, setNodes)}
  style={{
    position: "absolute",
    top: 20,
    right: 20,
    zIndex: 10,
    padding: "8px 16px",
    backgroundColor: "#4f46e5",
    color: "#fff",
    border: "none",
    borderRadius: "6px",
    cursor: "pointer",
    fontWeight: "600",
    boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
    transition: "all 0.2s ease",
  }}
  onMouseEnter={(e) => e.currentTarget.style.backgroundColor = "#4338ca"}
  onMouseLeave={(e) => e.currentTarget.style.backgroundColor = "#4f46e5"}
>
  Submit Pipeline
</button>
